import{_ as a,o as e,c as i,ah as t}from"./chunks/framework.BrHDBe7t.js";const u=JSON.parse('{"title":"事件循环","description":"","frontmatter":{},"headers":[{"level":2,"title":"进程和线程的基本概念","slug":"进程和线程的基本概念","link":"#进程和线程的基本概念","children":[{"level":3,"title":"什么是进程","slug":"什么是进程","link":"#什么是进程","children":[]},{"level":3,"title":"什么是线程","slug":"什么是线程","link":"#什么是线程","children":[]},{"level":3,"title":"线程与进程的关键关系","slug":"线程与进程的关键关系","link":"#线程与进程的关键关系","children":[]},{"level":3,"title":"进程与线程的主要区别","slug":"进程与线程的主要区别","link":"#进程与线程的主要区别","children":[]}]},{"level":2,"title":"浏览器进程模型","slug":"浏览器进程模型","link":"#浏览器进程模型","children":[]},{"level":2,"title":"渲染主线程如何工作？","slug":"渲染主线程如何工作","link":"#渲染主线程如何工作","children":[]},{"level":2,"title":"核心概念","slug":"核心概念","link":"#核心概念","children":[]},{"level":2,"title":"事件循环的组成","slug":"事件循环的组成","link":"#事件循环的组成","children":[{"level":3,"title":"调用栈（Call Stack）","slug":"调用栈-call-stack","link":"#调用栈-call-stack","children":[]},{"level":3,"title":"任务队列（Task Queue）","slug":"任务队列-task-queue","link":"#任务队列-task-queue","children":[]},{"level":3,"title":"Web APIs / C++ APIs","slug":"web-apis-c-apis","link":"#web-apis-c-apis","children":[]}]},{"level":2,"title":"宏任务（Macrotasks）","slug":"宏任务-macrotasks","link":"#宏任务-macrotasks","children":[]},{"level":2,"title":"微任务（Microtasks）","slug":"微任务-microtasks","link":"#微任务-microtasks","children":[]},{"level":2,"title":"事件循环执行顺序","slug":"事件循环执行顺序","link":"#事件循环执行顺序","children":[]}],"relativePath":"javascript/core/事件循环.md","filePath":"javascript/core/事件循环.md"}'),r={name:"javascript/core/事件循环.md"};function s(n,l,d,o,c,h){return e(),i("div",null,[...l[0]||(l[0]=[t('<h1 id="事件循环" tabindex="-1">事件循环 <a class="header-anchor" href="#事件循环" aria-label="Permalink to “事件循环”">​</a></h1><h2 id="进程和线程的基本概念" tabindex="-1">进程和线程的基本概念 <a class="header-anchor" href="#进程和线程的基本概念" aria-label="Permalink to “进程和线程的基本概念”">​</a></h2><h3 id="什么是进程" tabindex="-1">什么是进程 <a class="header-anchor" href="#什么是进程" aria-label="Permalink to “什么是进程”">​</a></h3><p>程序运行需要有它自己专属的内存空间，可以把这块内存空间简单理解为进程。</p><p>进程是操作系统进行<strong>资源分配</strong>和<strong>调度</strong>的基本单位。</p><h3 id="什么是线程" tabindex="-1">什么是线程 <a class="header-anchor" href="#什么是线程" aria-label="Permalink to “什么是线程”">​</a></h3><p>线程是进程内部的一个执行路径，是<strong>CPU调度</strong>和<strong>执行</strong>的最小单位。</p><h3 id="线程与进程的关键关系" tabindex="-1">线程与进程的关键关系 <a class="header-anchor" href="#线程与进程的关键关系" aria-label="Permalink to “线程与进程的关键关系”">​</a></h3><ul><li>一个进程可以包含多个线程。</li><li>同一个进程里的所有线程，共享该进程的资源（如内存地址空间、打开的文件、全局变量等）。这意味着线程之间可以非常方便地通信，但同时也带来了“数据混乱”的风险（需要引入锁等同步机制）。</li><li>线程自己只拥有一些运行时必不可少的资源，比如自己的程序计数器（记录执行到哪一行）、一组寄存器和自己的栈（用于存放局部变量）。这些是保证它能独立执行的基础。</li></ul><h3 id="进程与线程的主要区别" tabindex="-1">进程与线程的主要区别 <a class="header-anchor" href="#进程与线程的主要区别" aria-label="Permalink to “进程与线程的主要区别”">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>进程</th><th>线程</th></tr></thead><tbody><tr><td>本质</td><td>资源分配的基本单位</td><td>CPU调度和执行的基本单位</td></tr><tr><td>资源</td><td>拥有独立的地址空间和系统资源</td><td>共享所属进程的地址空间和资源</td></tr><tr><td>通信</td><td>进程间通信（IPC）复杂，需要特殊机制（如管道、消息队列）</td><td>线程间通信非常简单，可以直接读写共享数据（但需注意同步）</td></tr><tr><td>开销</td><td>创建和销毁进程的开销大</td><td>创建和销毁线程的开销小</td></tr><tr><td>独立性</td><td>进程之间相互独立，一个进程崩溃一般不会影响其他进程</td><td>一个线程崩溃很可能导致其所属的整个进程崩溃</td></tr></tbody></table><h2 id="浏览器进程模型" tabindex="-1">浏览器进程模型 <a class="header-anchor" href="#浏览器进程模型" aria-label="Permalink to “浏览器进程模型”">​</a></h2><p><strong>浏览器是一个多进程多线程的应用程序。</strong></p><p>浏览器内部工作及其复杂。为了避免相互影响，减少连环崩溃的几率，当启动浏览器后，它会自动启动多个进程。</p><p>其中，最主要的进程有：</p><ol><li>浏览器进程（Browser Process） 主要负责界面显示，用户交互，子进程管理等。浏览器进程内部会启动多个线程处理不同的任务。</li><li>网络进程 负责加载网络资源。网络进程内部会启动多个线程来处理不同的网络任务。</li><li><strong>渲染进程（重要）</strong> 渲染进程启动后，会开启一个<strong>渲染主线程</strong>，主线程负责执行 HTML，CSS，JS 代码。 默认情况下，浏览器会为每一个标签页开启一个新的渲染进程，以保证不同的标签页之间不会互相影响。</li></ol><h2 id="渲染主线程如何工作" tabindex="-1">渲染主线程如何工作？ <a class="header-anchor" href="#渲染主线程如何工作" aria-label="Permalink to “渲染主线程如何工作？”">​</a></h2><p>渲染主线程是浏览器最繁忙的线程，需要它处理的任务包括但不限于：</p><ul><li>解析 HTML</li><li>解析 CSS</li><li>布局</li><li>处理图层</li><li>执行全局 JS 代码</li><li>执行事件处理函数</li><li>执行计时器回调函数</li><li>。。。。</li></ul><blockquote><p>思考：为什么渲染线程不适用多个线程来处理这些事情？</p></blockquote><p>要出来这么多任务，主线程遇到了一个前所未有的难题：如何调度任务？</p><p>比如：</p><ul><li>我正在执行一个 JS 函数，执行到一半的时候用户点击了按钮，我该立即去执行点击事件的处理函数吗？</li><li>我正在执行一个 JS 函数，执行到一半的时候某个计时器到达了时间，我该立即去执行它的回调函数吗？</li><li>浏览器进程通知我 “用户点击了按钮”，与此同时，某个计时器也到达了时间，我该处理哪一个？</li></ul><p>渲染主线程想出了一个绝妙的主意来处理这个问题：<strong>排队</strong></p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to “核心概念”">​</a></h2><p>JavaScript 是单线程的，这意味着它一次只能执行一个任务。事件循环（Event Loop）是 JavaScript 处理异步操作的机制，使得非阻塞 I/O 成为可能。</p><h2 id="事件循环的组成" tabindex="-1">事件循环的组成 <a class="header-anchor" href="#事件循环的组成" aria-label="Permalink to “事件循环的组成”">​</a></h2><h3 id="调用栈-call-stack" tabindex="-1">调用栈（Call Stack） <a class="header-anchor" href="#调用栈-call-stack" aria-label="Permalink to “调用栈（Call Stack）”">​</a></h3><ul><li>后进先出（LIFO）的数据结构</li><li>存储函数的执行上下文</li><li>同步任务按顺序执行</li></ul><h3 id="任务队列-task-queue" tabindex="-1">任务队列（Task Queue） <a class="header-anchor" href="#任务队列-task-queue" aria-label="Permalink to “任务队列（Task Queue）”">​</a></h3><ul><li>先进先出（FIFO）的数据结构</li><li>存储异步任务的回调函数</li><li>分为宏任务队列和微任务队列</li></ul><h3 id="web-apis-c-apis" tabindex="-1">Web APIs / C++ APIs <a class="header-anchor" href="#web-apis-c-apis" aria-label="Permalink to “Web APIs / C++ APIs”">​</a></h3><ul><li>浏览器提供的异步 API</li><li>Node.js 的 C++ 扩展</li></ul><p>例如：setTimeout、DOM 事件、AJAX、文件读写</p><h2 id="宏任务-macrotasks" tabindex="-1">宏任务（Macrotasks） <a class="header-anchor" href="#宏任务-macrotasks" aria-label="Permalink to “宏任务（Macrotasks）”">​</a></h2><ul><li>setTimeout、setInterval</li><li>setImmediate（Node.js）</li><li>I/O 操作</li><li>UI 渲染（浏览器）</li><li>requestAnimationFrame（浏览器）</li><li>script（整体代码）</li></ul><h2 id="微任务-microtasks" tabindex="-1">微任务（Microtasks） <a class="header-anchor" href="#微任务-microtasks" aria-label="Permalink to “微任务（Microtasks）”">​</a></h2><ul><li>Promise.then()、Promise.catch()、Promise.finally()</li><li>async/await</li><li>MutationObserver（浏览器）</li><li>process.nextTick（Node.js，优先级最高）</li><li>queueMicrotask()</li></ul><h2 id="事件循环执行顺序" tabindex="-1">事件循环执行顺序 <a class="header-anchor" href="#事件循环执行顺序" aria-label="Permalink to “事件循环执行顺序”">​</a></h2><ol><li>执行同步代码，这些代码会进入调用栈，直到栈为空。</li><li>处理微任务（microtasks）：在调用栈为空后，JavaScript引擎会检查微任务队列，并依次执行微任务，直到微任务队列为空。</li><li>执行渲染（如果需要）：在浏览器环境中，如果当前需要更新渲染，则会执行渲染操作。</li><li>从宏任务队列中取出一个任务执行。</li><li>重复步骤2到4。</li></ol>',40)])])}const p=a(r,[["render",s]]);export{u as __pageData,p as default};
